// Collect all articles from all RSS feeds and build Claude request
const allItems = $input.all();

// Detect source from article link domain
const getSource = (link) => {
  try {
    const hostname = new URL(link).hostname.replace('www.', '');
    const map = {
      'techcrunch.com': 'TechCrunch',
      'venturebeat.com': 'VentureBeat',
      'artificialintelligence-news.com': 'AI News',
      'technologyreview.com': 'MIT Tech Review',
      'reuters.com': 'Reuters',
      'cnbc.com': 'CNBC',
      'news.google.com': 'Google News',
    };
    return map[hostname] || hostname;
  } catch { return 'Unknown'; }
};

const articles = allItems
  .map(item => ({
    title: String(item.json.title || '').trim(),
    link: String(item.json.link || '').trim(),
    description: String(item.json.contentSnippet || item.json.content || '')
      .replace(/<[^>]*>/g, '').slice(0, 400).trim(),
    source: getSource(String(item.json.link || '')),
    pubDate: String(item.json.pubDate || item.json.isoDate || ''),
  }))
  .filter(a => a.title && a.link)
  // Keep only articles from the last 3 days
  .filter(a => {
    if (!a.pubDate) return false;
    const pub = new Date(a.pubDate);
    const cutoff = new Date(Date.now() - 3 * 24 * 60 * 60 * 1000);
    return pub >= cutoff;
  })
  // Remove duplicates by title
  .filter((a, i, arr) => arr.findIndex(b => b.title === a.title) === i)
  .slice(0, 60);

console.log(`Articles after date filter (last 3 days): ${articles.length}`);

if (articles.length === 0) {
  throw new Error('No articles found from any feed. Check individual RSS nodes for errors.');
}

const prompt = `Tu es un curateur d'actualités IA pour un créateur de contenu francophone (@manu_ai.to) qui fait des vidéos pour des entrepreneurs sur l'IA et l'automatisation.

Voici une liste d'articles récents. Sélectionne les meilleurs et classe-les dans ces 4 catégories :

1. CASE_STUDY — Entreprises qui ont remplacé des employés par l'IA, réduit leurs coûts, automatisé des processus avec des chiffres concrets (nb d'employés, montants économisés, %). PRIORITÉ ABSOLUE — si tu en trouves, ils vont en premier.
2. OUTIL — Lancement ou mise à jour majeure d'un outil / modèle IA avec un impact business clair.
3. DEBAT — Sujets de société, régulation, débats autour de l'IA (remplacement des emplois, éthique, futur du travail).
4. NEWS — Autres actualités IA intéressantes qui ne rentrent pas dans les catégories ci-dessus.

Règles de sélection :
- Sélectionne max 5 articles par catégorie (moins si pas assez de bons articles)
- CASE_STUDY : inclure uniquement si tu as des chiffres précis ou un nom d'entreprise identifiable
- Ignore les articles vagues, les opinions sans faits, les rumeurs non sourcées
- Pour chaque article, écris un résumé en français de 2-3 lignes
- Pour chaque CASE_STUDY, ajoute un champ "angle_video" : une phrase courte suggérant l'angle de réaction pour Manu (ex: "Comment [Entreprise X] a économisé Y millions en automatisant Z — et ce que ça dit du marché")

Réponds UNIQUEMENT avec du JSON valide, sans markdown, sans code block :
{
  "case_studies": [{"title": "...", "source": "...", "link": "...", "summary_fr": "...", "angle_video": "..."}],
  "outils": [{"title": "...", "source": "...", "link": "...", "summary_fr": "..."}],
  "debats": [{"title": "...", "source": "...", "link": "...", "summary_fr": "..."}],
  "news": [{"title": "...", "source": "...", "link": "...", "summary_fr": "..."}]
}

Articles disponibles :
${JSON.stringify(articles)}`;

const body = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 8192,
  messages: [{ role: 'user', content: prompt }]
});

return [{ json: { body } }];

// Parse Claude response and build categorized HTML email
const responseText = $json.content[0].text;

// Try multiple strategies to extract valid JSON
let digest;
const strategies = [
  () => {
    const clean = responseText.replace(/```json?\n?/g, '').replace(/```/g, '').trim();
    return JSON.parse(clean);
  },
  () => {
    const start = responseText.indexOf('{');
    const end = responseText.lastIndexOf('}');
    if (start === -1 || end === -1) throw new Error('No JSON braces found');
    return JSON.parse(responseText.slice(start, end + 1));
  },
];

for (const strategy of strategies) {
  try { digest = strategy(); break; } catch (e) { continue; }
}

if (!digest) {
  throw new Error(`JSON parse failed. Claude response: ${responseText.slice(0, 400)}`);
}

const today = new Date().toLocaleDateString('fr-FR', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Helper: render a standard article card
const articleCard = (a, i) => `
  <div style="margin-bottom:20px;padding-bottom:20px;border-bottom:1px solid #e5e7eb;">
    <div style="font-size:11px;color:#6b7280;text-transform:uppercase;letter-spacing:0.06em;margin-bottom:4px;">${a.source}</div>
    <h3 style="margin:0 0 6px 0;font-size:15px;font-weight:600;line-height:1.4;">
      <a href="${a.link}" style="color:#111827;text-decoration:none;">${i + 1}. ${a.title}</a>
    </h3>
    <p style="margin:0;color:#4b5563;font-size:13px;line-height:1.7;">${a.summary_fr}</p>
    <a href="${a.link}" style="display:inline-block;margin-top:6px;font-size:12px;color:#7c3aed;text-decoration:none;">Lire l'article →</a>
  </div>
`;

// Helper: render a case study card (has angle_video)
const caseStudyCard = (a, i) => `
  <div style="margin-bottom:20px;padding:16px;background:#fefce8;border:1px solid #fde047;border-radius:8px;">
    <div style="font-size:11px;color:#92400e;text-transform:uppercase;letter-spacing:0.06em;margin-bottom:4px;">${a.source}</div>
    <h3 style="margin:0 0 6px 0;font-size:15px;font-weight:600;line-height:1.4;">
      <a href="${a.link}" style="color:#111827;text-decoration:none;">${i + 1}. ${a.title}</a>
    </h3>
    <p style="margin:0 0 8px 0;color:#4b5563;font-size:13px;line-height:1.7;">${a.summary_fr}</p>
    ${a.angle_video ? `<div style="background:#fff;border-left:3px solid #f59e0b;padding:8px 12px;border-radius:0 4px 4px 0;">
      <span style="font-size:11px;font-weight:700;color:#92400e;text-transform:uppercase;">Angle vidéo →</span>
      <p style="margin:2px 0 0;font-size:13px;color:#1c1917;font-style:italic;">${a.angle_video}</p>
    </div>` : ''}
    <a href="${a.link}" style="display:inline-block;margin-top:8px;font-size:12px;color:#7c3aed;text-decoration:none;">Lire l'article →</a>
  </div>
`;

// Build each section (skip if empty)
const sections = [];

if (digest.case_studies && digest.case_studies.length > 0) {
  sections.push(`
    <div style="margin-bottom:36px;">
      <h2 style="margin:0 0 16px 0;font-size:18px;font-weight:800;padding:10px 14px;background:#fde047;border-radius:6px;display:inline-block;">🏢 Case Studies Business</h2>
      <p style="margin:0 0 16px 0;font-size:12px;color:#6b7280;">Entreprises + chiffres concrets — idéal pour des vidéos de réaction</p>
      ${digest.case_studies.map((a, i) => caseStudyCard(a, i)).join('')}
    </div>
  `);
}

if (digest.outils && digest.outils.length > 0) {
  sections.push(`
    <div style="margin-bottom:36px;">
      <h2 style="margin:0 0 16px 0;font-size:18px;font-weight:800;padding:10px 14px;background:#dbeafe;border-radius:6px;display:inline-block;">🚀 Nouveaux Outils & Modèles</h2>
      ${digest.outils.map((a, i) => articleCard(a, i)).join('')}
    </div>
  `);
}

if (digest.debats && digest.debats.length > 0) {
  sections.push(`
    <div style="margin-bottom:36px;">
      <h2 style="margin:0 0 16px 0;font-size:18px;font-weight:800;padding:10px 14px;background:#fce7f3;border-radius:6px;display:inline-block;">💬 Débats & Tendances</h2>
      ${digest.debats.map((a, i) => articleCard(a, i)).join('')}
    </div>
  `);
}

if (digest.news && digest.news.length > 0) {
  sections.push(`
    <div style="margin-bottom:36px;">
      <h2 style="margin:0 0 16px 0;font-size:18px;font-weight:800;padding:10px 14px;background:#f3f4f6;border-radius:6px;display:inline-block;">📰 News Générales</h2>
      ${digest.news.map((a, i) => articleCard(a, i)).join('')}
    </div>
  `);
}

const caseStudyCount = (digest.case_studies || []).length;
const subjectPrefix = caseStudyCount > 0 ? `🏢 ${caseStudyCount} case study · ` : '';

const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:640px;margin:0 auto;padding:32px 24px;background:#fff;color:#111827;">
  <div style="border-bottom:3px solid #111827;padding-bottom:20px;margin-bottom:36px;">
    <h1 style="margin:0;font-size:28px;font-weight:800;letter-spacing:-0.02em;">Morgans Report</h1>
    <p style="margin:6px 0 0;color:#6b7280;font-size:14px;">${today}</p>
  </div>
  ${sections.join('')}
  <div style="margin-top:36px;padding-top:16px;border-top:1px solid #e5e7eb;font-size:11px;color:#9ca3af;text-align:center;">
    Généré automatiquement à 5h &bull; TechCrunch &middot; VentureBeat &middot; Reuters &middot; CNBC &middot; MIT Tech Review &middot; AI News &middot; Google News
  </div>
</body></html>`;

return [{ json: { html, subject: `${subjectPrefix}Morgans Report — ${today}` } }];
